    def _vs3_unique_refs(values: list[Any]) -> list[str]:
        refs: list[str] = []
        seen: set[str] = set()
        for value in values:
            if value is None:
                continue
            ref = str(value)
            if ref not in seen:
                refs.append(ref)
                seen.add(ref)
        return refs

